document.addEventListener('DOMContentLoaded', () => {
const prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

const navToggle = document.getElementById('navToggle');
const navLinks = document.getElementById('navLinks');
const navbar = document.getElementById('navbar');

const copyEmail = document.getElementById('copyEmail');
if (copyEmail) {
const status = copyEmail.querySelector('.contact__copy-status');
copyEmail.addEventListener('click', async () => {
const email = copyEmail.getAttribute('data-email');
try {
await navigator.clipboard.writeText(email);
if (status) {
status.textContent = 'Copied';
setTimeout(() => { status.textContent = ''; }, 2000);
}
} catch (e) {
if (status) status.textContent = 'Copy failed';
}
});
}





const themeToggle = document.getElementById('themeToggle');
if (themeToggle) {
const root = document.documentElement;
const mq = window.matchMedia('(prefers-color-scheme: dark)');

const effectiveIsDark = () => {
const saved = root.getAttribute('data-theme');
if (saved === 'dark') return true;
if (saved === 'light') return false;
return mq.matches;
};
const syncThemeButton = () => {
const isDark = effectiveIsDark();
themeToggle.setAttribute('aria-pressed', String(isDark));
themeToggle.setAttribute(
'aria-label',
isDark ? 'Switch to light mode' : 'Switch to dark mode'
);
};
syncThemeButton();


if (mq.addEventListener) mq.addEventListener('change', syncThemeButton);
else if (mq.addListener) mq.addListener(syncThemeButton);
themeToggle.addEventListener('click', () => {
const next = effectiveIsDark() ? 'light' : 'dark';
root.setAttribute('data-theme', next);
try { localStorage.setItem('theme', next); } catch (e) {}
syncThemeButton();
});
}
if (navToggle && navLinks) {

let lastFocused = null;
const focusable = () =>
[...navLinks.querySelectorAll('a'), navToggle]
.filter(el => el.offsetParent !== null);
const trapFocus = (e) => {
if (e.key !== 'Tab' || !navLinks.classList.contains('open')) return;
const items = focusable();
if (!items.length) return;
const first = items[0];
const last = items[items.length - 1];
if (e.shiftKey && document.activeElement === first) {
e.preventDefault();
last.focus();
} else if (!e.shiftKey && document.activeElement === last) {
e.preventDefault();
first.focus();
}
};
const toggleMenu = (forceClose = false) => {
const isOpen = forceClose ? false : !navLinks.classList.contains('open');
navLinks.classList.toggle('open', isOpen);
navToggle.classList.toggle('open', isOpen);
navToggle.setAttribute('aria-expanded', String(isOpen));
document.body.style.overflow = isOpen ? 'hidden' : '';
syncToTop();
if (isOpen) {
lastFocused = document.activeElement;
const firstLink = navLinks.querySelector('a');
if (firstLink) firstLink.focus();
} else if (lastFocused && typeof lastFocused.focus === 'function') {
lastFocused.focus();
lastFocused = null;
}
};
navToggle.addEventListener('click', () => toggleMenu());
navLinks.querySelectorAll('a').forEach(link => {
link.addEventListener('click', () => toggleMenu(true));
});
document.addEventListener('keydown', (e) => {
if (e.key === 'Escape') toggleMenu(true);
else trapFocus(e);
});
}

const toTop = document.getElementById('toTop');


const syncToTop = () => {
if (!toTop) return;
if (navLinks && navLinks.classList.contains('open')) {
toTop.setAttribute('hidden', '');
} else if (window.pageYOffset > 600) {
toTop.removeAttribute('hidden');
}
};
if (toTop) {
let toTopTicking = false;
const onToTopScroll = () => {
if (window.pageYOffset > 600) toTop.removeAttribute('hidden');
else toTop.setAttribute('hidden', '');
toTopTicking = false;
};
window.addEventListener('scroll', () => {
if (!toTopTicking) {
requestAnimationFrame(onToTopScroll);
toTopTicking = true;
}
}, { passive: true });
syncToTop();
toTop.addEventListener('click', () => {
window.scrollTo({ top: 0, behavior: prefersReducedMotion ? 'auto' : 'smooth' });
});
onToTopScroll();
}

if (navbar) {
let lastY = window.pageYOffset;
let ticking = false;
function onNavScroll() {
const y = window.pageYOffset;
const goingDown = y > lastY;
if (y <= 0) {
navbar.classList.remove('nav--hidden');
navbar.style.boxShadow = 'none';
} else {
navbar.style.boxShadow = '0 10px 30px -10px var(--nav-shadow)';

if (goingDown && y > 80 && (!navLinks || !navLinks.classList.contains('open'))) {
navbar.classList.add('nav--hidden');
} else if (!goingDown) {
navbar.classList.remove('nav--hidden');
}
}
lastY = y;
ticking = false;
}
window.addEventListener('scroll', () => {
if (!ticking) {
requestAnimationFrame(onNavScroll);
ticking = true;
}
}, { passive: true });
onNavScroll();
}

if (typeof ScrollEffects !== 'undefined') ScrollEffects.init();

document.querySelectorAll('a[href^="#"]').forEach((anchor) => {
anchor.addEventListener('click', (e) => {
const href = anchor.getAttribute('href');
if (href === '#' || !href.startsWith('#')) return;
const target = document.querySelector(href);
if (target) {
e.preventDefault();
navbar.classList.remove('nav--hidden');
const navHeight = navbar.offsetHeight;
const targetPosition = target.getBoundingClientRect().top + window.pageYOffset - navHeight;
window.scrollTo({
top: targetPosition,
behavior: prefersReducedMotion ? 'auto' : 'smooth'
});
}
});
});
});